oxy_webhelp_navlinks = {"aws_workloads_protection_setup-d26997e13454":{"topics":[{"title":"SLA Domain assignment hierarchy for AWS","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides hierarchy-based, automatic protection for AWS workloads,         simplifying the assignment of protection across various levels, such as AWS accounts and         individual workloads.<\/p>","href":"saas\/aws_hierarchy_sla_assignment.html","attributes":{"data-id":"aws_hierarchy_sla_assignment"},"menu":{"hasChildren":false},"tocID":"aws_hierarchy_sla_assignment-d26997e13465","topics":[]},{"title":"Best practices for AWS SLA Domain assignment","shortdesc":"<p class=\"shortdesc\">Information about the best practices for assigning SLA Domains to AWS workloads,         ensuring effective data protection and compliance.<\/p>","href":"saas\/aws_best_practices_sla_assignment.html","attributes":{"data-id":"aws_best_practices_sla_assignment"},"menu":{"hasChildren":false},"tocID":"aws_best_practices_sla_assignment-d26997e13478","topics":[]},{"title":"Evaluation of SLA Domain options for AWS","shortdesc":"<p class=\"shortdesc\">Understanding the various protection options is important when creating an SLA Domain         for your AWS workloads. This ensures alignment with organizational needs. Thoroughly         evaluating these options enables informed decisions and provides effective protection for         the workloads.<\/p>","href":"saas\/aws_evaluate_sla_option.html","attributes":{"data-id":"aws_evaluate_sla_option"},"menu":{"hasChildren":false},"tocID":"aws_evaluate_sla_option-d26997e13489","next":"aws_evaluate_sla_option-d26997e13489"},{"title":"AWS protection limitations","shortdesc":"<p class=\"shortdesc\">Information about <span class=\"ph\">RSC<\/span> limitations for AWS protection and         recovery.<\/p>","href":"saas\/aws_protection_limitations.html","attributes":{"data-id":"aws_protection_limitations"},"menu":{"hasChildren":false},"tocID":"aws_protection_limitations-d26997e13664","topics":[]},{"title":"Region level SLA Domain assignment for AWS","shortdesc":"<p class=\"shortdesc\">You can apply a unified policy to an entire AWS region with a region-level SLA Domain         assignment, ensuring any new resource in that region is automatically protected.<\/p>","href":"saas\/aws_region_level_sla_domain_assignment.html","attributes":{"data-id":"aws_region_level_sla_domain_assignment"},"menu":{"hasChildren":false},"tocID":"aws_region_level_sla_domain_assignment-d26997e13678","topics":[]},{"title":"Configuration of AWS protection","shortdesc":"<p class=\"shortdesc\">After you have decided on the protection policies you want to configure, you can         begin configuration by creating an SLA Domain and assigning protection to AWS workloads and         AWS accounts.<\/p>","href":"saas\/aws_protection_config.html","attributes":{"data-id":"aws_protection_config"},"menu":{"hasChildren":false},"tocID":"aws_protection_config-d26997e13689","next":"aws_protection_config-d26997e13689"}]}};